import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function AddTask({ closeModal, onTaskAdded }) {
  const [formData, setFormData] = useState({
    title: "",
    dueDate: "",
    priority: "MEDIUM",
    category: "",
    completed: false,
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!formData.title || !formData.dueDate) {
      setError("Please fill required fields");
      return;
    }

    try {
      const res = await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({
          ...formData,
          autoGenerated: false,
          suggestionSource: null,
          notified: false
        })
      });

      if (res.ok) {
        setSuccess("Task added successfully!");

        setFormData({
          title: "",
          dueDate: "",
          priority: "MEDIUM",
          category: "",
          completed: false,
        });

        if (onTaskAdded) onTaskAdded();

        setTimeout(() => {
          closeModal();
        }, 1200);
      } else {
        setError("Failed to add task");
      }
    } catch (err) {
      setError("Server error");
    }
  };

  return (
    <div className="w-[420px] p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl relative">

      {/* Close */}
      <button
        onClick={closeModal}
        className="absolute top-3 right-3 text-white hover:text-red-400"
      >
        <XMarkIcon className="w-6 h-6" />
      </button>

      <h2 className="text-2xl font-bold text-white text-center mb-6">
        Add Task
      </h2>

      {success && <p className="text-green-300 text-center mb-3">{success}</p>}
      {error && <p className="text-red-300 text-center mb-3">{error}</p>}

      <form onSubmit={handleAdd} className="space-y-4">

        <input
          type="text"
          name="title"
          placeholder="Task Title"
          value={formData.title}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white placeholder-white/70 outline-none focus:ring-2 focus:ring-white"
        />

        <input
          type="date"
          name="dueDate"
          value={formData.dueDate}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white outline-none focus:ring-2 focus:ring-white"
        />

        <select
          name="priority"
          value={formData.priority}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white outline-none"
        >
          <option value="LOW" className="text-black">Low</option>
          <option value="MEDIUM" className="text-black">Medium</option>
          <option value="HIGH" className="text-black">High</option>
        </select>

        <input
          type="text"
          name="category"
          placeholder="Category"
          value={formData.category}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg bg-white/30 text-white placeholder-white/70 outline-none focus:ring-2 focus:ring-white"
        />

        <label className="flex items-center gap-2 text-white">
          <input
            type="checkbox"
            name="completed"
            checked={formData.completed}
            onChange={handleChange}
          />
          Completed
        </label>

        <button
          type="submit"
          className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-white font-semibold transition"
        >
          Add Task
        </button>
      </form>
    </div>
  );
}
